import heapq

class Solution:
    def nthUglyNumber(self, n: int) -> int:
        min_heap = [1]
        seen = {1}

        factors = [2, 3, 5]

        current_ugly = 1

        for _ in range(n):
            current_ugly = heapq.heappop(min_heap)

            for factor in factors:
                next_ugly = current_ugly * factor
                if next_ugly not in seen:
                    seen.add(next_ugly)
                    heapq.heappush(min_heap, next_ugly)

        return current_ugly
